var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`응? 종신계약?`,JPN:`えっ？　終身契約？`,ENG:`Mm? A lifetime contract?`,TWN:`嗯？終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`어허- 사장님, 이런 종이쪼가리가 없어도 기사는 구두서약만으로 목숨을 거는 법이라구.`,JPN:`わかってないなー、社長は。こんな紙切れなんかなくたって、騎士は口頭での誓約だけでも命を張れるのにさ。`,ENG:`Come on, Boss. The words of us knights are as good as a piece of paper like this.`,TWN:`吼，老闆，就算沒有白紙黑字，我們騎士光是用口頭發誓，就會賭上性命了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`뭐, 그래도 이렇게 해야 사장님 마음이 편해지는 거라면 얼마든지!`,JPN:`まあ、これで社長の気が済むんだったら、いくらでも契約しちゃうけどね！`,ENG:`Well, but if it makes you feel comfortable, then sure, I'll sign it.`,TWN:`好吧，如果這麼做老闆心裡能舒服一些，那當然沒問題！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`난 예전부터 사장님이 정말 마음에 들었거든.`,JPN:`私、前から社長のことがすごく気に入ってるんだよ。`,ENG:`You know, I took a shine to you pretty quickly.`,TWN:`我從以前就很喜歡老闆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`여기서 하는 일들도 보람차고. 먹을 것도 잘 챙겨주잖아?`,JPN:`ここではやりがいのある仕事もあるし、しっかり食べさせてもらえるでしょ？`,ENG:`I like what I do here, and you feed us well, too.`,TWN:`這裡的工作也很有意義，而且老闆在吃的方面不是很照顧我嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`회사랑 멋대로 계약을 했다고 하면 부단장한테 또 한 소리 듣겠지만......`,JPN:`会社と勝手に契約をしたことがバレたら、副団長がまたガミガミ言うだろうけど……`,ENG:`I probably won't hear the end of it if the Deputy Captain finds out that I signed the contract without telling her first,`,TWN:`隨便跟公司簽訂契約，會被副團長罵吧，但是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LIV_ZODIAC_SUMMER_NULL`,text:{KOREA:`으헤헤, 그건 그때 가서 생각하지 뭐-`,JPN:`えへへ、そんときはそんときってことで！`,ENG:`but oh, well. I'll cross that bridge when I come to it.`,TWN:`嘿嘿，這種事到時候再說就好啦。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LIV_ZODIAC_SUMMER_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};